// api/partner-image.js
// Gemini Vision : détection plaque + positionnement voiture
// CommonJS format pour Vercel

const AUTOEASY_BG_B64 = "";

module.exports = async function handler(req, res) {
  if (req.method !== "POST") {
    return res.status(405).json({ error: "Method not allowed" });
  }

  const { imageBase64, mimeType } = req.body;
  if (!imageBase64) return res.status(400).json({ error: "Missing imageBase64" });

  const GEMINI_KEY = process.env.GEMINI_API_KEY;

  const prompt = `Tu es un expert en analyse d'images pour des montages photographiques professionnels automobiles.
Le fond de destination est un showroom avec ces caractéristiques :
- Sol damier vert/noir brillant qui commence à environ 58% de la hauteur de l'image (y = 0.58)
- Mur végétal à gauche
- Enseigne AUTOEASY lumineuse au centre-droite
- Dimensions du canvas final : 1024x768 pixels
Analyse la photo source (deuxième image) et retourne UNIQUEMENT un objet JSON valide. Ne génère aucun texte avant ou après, et n'utilise pas de balises markdown. Le JSON doit strictement respecter cette structure :
{"plates":[{"ymin":0.0,"xmin":0.0,"ymax":0.0,"xmax":0.0}],"carSourceBox":{"ymin":0.0,"xmin":0.0,"ymax":0.0,"xmax":0.0},"carPlacement":{"solRatio":0.62,"scaleRatio":0.75,"offsetXRatio":0.02},"carAngle":"three_quarter_front","lighting":{"sourceDirection":"left","shadowIntensity":0.5}}`;

  try {
    const geminiRes = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${GEMINI_KEY}`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          contents: [{
            parts: [
              { inline_data: { mime_type: "image/jpeg", data: AUTOEASY_BG_B64 } },
              { text: "Voici le fond showroom AutoEasy de destination." },
              { inline_data: { mime_type: mimeType || "image/jpeg", data: imageBase64 } },
              { text: prompt },
            ],
          }],
          generationConfig: { temperature: 0.1, maxOutputTokens: 1024 },
        }),
      }
    );

    if (!geminiRes.ok) {
      const errText = await geminiRes.text();
      console.error("Gemini error:", geminiRes.status, errText);
      return res.status(200).json({
        plateBox: null, plates: [],
        carPlacement: { solRatio: 0.62, scaleRatio: 0.75, offsetXRatio: 0.02 },
      });
    }

    const data = await geminiRes.json();
    const raw = data.candidates?.[0]?.content?.parts?.[0]?.text || "";
    console.log("Gemini raw:", raw.slice(0, 300));

    const s = raw.indexOf("{");
    const e = raw.lastIndexOf("}");
    if (s === -1 || e === -1) {
      return res.status(200).json({
        plateBox: null, plates: [],
        carPlacement: { solRatio: 0.62, scaleRatio: 0.75, offsetXRatio: 0.02 },
      });
    }

    const parsed = JSON.parse(raw.slice(s, e + 1));
    const plates = (parsed.plates || []).map(p => ({
      x: p.xmin, y: p.ymin,
      w: p.xmax - p.xmin,
      h: p.ymax - p.ymin,
    }));

    const cp = parsed.carPlacement || {};
    const carPlacement = {
      solRatio:     Math.min(0.72, Math.max(0.50, cp.solRatio     || 0.62)),
      scaleRatio:   Math.min(0.85, Math.max(0.55, cp.scaleRatio   || 0.75)),
      offsetXRatio: Math.min(0.10, Math.max(-0.10, cp.offsetXRatio || 0.02)),
    };

    return res.status(200).json({
      plateBox: plates[0] || null,
      plates,
      carPlacement,
      carSourceBox: parsed.carSourceBox || null,
      carAngle: parsed.carAngle || "three_quarter_front",
      lighting: parsed.lighting || { sourceDirection: "diffuse", shadowIntensity: 0.5 },
      plateDetected: plates.length > 0,
    });

  } catch (err) {
    console.error("partner-image error:", err.message);
    return res.status(200).json({
      plateBox: null, plates: [],
      carPlacement: { solRatio: 0.62, scaleRatio: 0.75, offsetXRatio: 0.02 },
      error: err.message
    });
  }
};